const input = $input.first().json;

// Dados do payload
const tipo = (input.tipo || input.body?.tipo || 'lead_qualificado').toLowerCase();
const nome = input.nome || input.body?.nome || 'Não informado';
const whatsapp = input.whatsapp || input.body?.whatsapp || '';
const email = input.email || input.body?.email || '';
const destinos = input.destinos || input.body?.destinos || '';
const dataChegada = input.data_chegada || input.body?.data_chegada || '';
const dataPartida = input.data_partida || input.body?.data_partida || '';
const numViajantes = input.num_viajantes || input.body?.num_viajantes || '';
const obs = input.observacoes || input.body?.observacoes || '';
const tituloTarefa = input.titulo_tarefa || input.body?.titulo_tarefa || '';
const vencimentoTarefa = input.vencimento_tarefa || input.body?.vencimento_tarefa || '';

// Número destino da notificação (admin/operador)
const destinatario = $env.NOTIFICACAO_WHATSAPP || $env.ADMIN_WHATSAPP || '5551990119605';

let mensagem = '';

if (tipo === 'lead_qualificado') {
  mensagem = `🔥 *NOVO LEAD QUALIFICADO*\n\n`;
  mensagem += `👤 ${nome}\n`;
  if (whatsapp) mensagem += `📱 ${whatsapp}\n`;
  if (email) mensagem += `📧 ${email}\n`;
  mensagem += `\n`;
  if (destinos) mensagem += `🗺️ Destino: ${destinos}\n`;
  if (dataChegada && dataPartida) {
    mensagem += `📅 ${dataChegada} a ${dataPartida}\n`;
  } else if (dataChegada) {
    mensagem += `📅 Chegada: ${dataChegada}\n`;
  }
  if (numViajantes) mensagem += `👥 ${numViajantes} viajante(s)\n`;
  if (obs) mensagem += `\n📝 ${obs}\n`;
  mensagem += `\n💬 A Bia já confirmou os dados.\nAcesse o CRM para enviar a proposta.`;

} else if (tipo === 'tarefa_criada') {
  mensagem = `📋 *NOVA TAREFA*\n\n`;
  if (tituloTarefa) mensagem += `📌 ${tituloTarefa}\n`;
  if (vencimentoTarefa) mensagem += `📅 Vencimento: ${vencimentoTarefa}\n`;
  if (nome) mensagem += `👤 Lead: ${nome}\n`;
  if (obs) mensagem += `\n📝 ${obs}`;

} else {
  // Notificação genérica
  mensagem = `📢 *NOTIFICAÇÃO CRM*\n\n`;
  if (nome) mensagem += `👤 ${nome}\n`;
  if (obs) mensagem += `\n${obs}`;
}

return [{
  json: {
    destinatario,
    mensagem,
    tipo,
    sucesso: true
  }
}];
